mapper.delete:
DELETE FROM favorites
WHERE user_id = #{userId}
  AND favorite_type = #{favoriteType}
  AND target_key = #{targetKey}

mapper.select:
SELECT f.*, p.title AS poem_title, p.dynasty AS poem_dynasty, p.author AS poem_author, p.content AS poem_content, p.tags AS poem_tags FROM favorites f LEFT JOIN poems p ON p.id = f.poem_id WHERE f.user_id = #{userId}
AND f.favorite_type = #{favoriteType}
ORDER BY f.created_at DESC
